INSERT INTO chatmessage (uid, fid, content, format, isread, addtime) VALUES
(18, 13, '陈曦你好！我看到你发布了考研英语辅导的技能，我最近正在备考，能聊聊你的教学方式吗？', 1, 1, '2026-04-26 09:15:00');
