(13, 18, '你好王浩！我主要针对阅读理解和写作两块，会根据你的基础定制复习计划，一般每周两次线上辅导。', 1, 1, '2026-04-26 09:18:00');
INSERT INTO chatmessage (uid, fid, content, format, isread, addtime) VALUES
